+/// tuple each count (round-12 OD/corpus `[41w, 51]` witness).
+fn ftup_walk(t: &str, in_tuple: bool, n: &mut i64) {
+    let t = t.trim();
+    if t.starts_with('<') && t.ends_with('>') && t.len() >= 2 {
+        for el in split_level(&t[1..t.len() - 1]) {
+            ftup_walk(el, true, n);
+        }
+        return;
+    }
